package com.finbit.fiuadapter.webservice.utils;

import java.nio.charset.StandardCharsets;
import java.util.Base64;

import com.finbit.fiuadapter.jwssignature.exception.JWSSignatureException;
import com.finbit.fiuadapter.jwssignature.util.JsonUtil;

/**
 * @author ashvinikumar
 * @version 1.0
 * @ fiu-adapter
 * @since 6/8/20
 */
public class Base64Decoder {

    public static Object getDecodedObject( String body, Class<?> type ) throws JWSSignatureException
    {
        return JsonUtil.convertJsonToObject(new String(Base64.getDecoder().decode(body), StandardCharsets.UTF_8),
                type);

    }

}
