    String schematicErrorCheck(FINotificationRequest fiNotificationRequest){
        HashMap<String, Object> stringObjectHashMap = new HashMap<>();
        String errorMessage = "";
        stringObjectHashMap.put("version", fiNotificationRequest.getVer());
        stringObjectHashMap.put("timeStamp", fiNotificationRequest.getTimestamp());
        stringObjectHashMap.put("txnId", fiNotificationRequest.getTxnid());
        stringObjectHashMap.put("notifier", fiNotificationRequest.getNotifier());
        stringObjectHashMap.put("fiNotificationRequest.FIStatus", fiNotificationRequest.getFIStatusNotification());
        stringObjectHashMap.put("fiNotificationRequest.FiStatusNotification.SessionId", fiNotificationRequest.getFIStatusNotification().getSessionId());
        stringObjectHashMap.put("fiNotificationRequest.FiStatusNotification.sessionStatus", fiNotificationRequest.getFIStatusNotification().getSessionStatus());
        stringObjectHashMap.put("fiNotificationRequest.FiStatusNotification.FIStatusResponse", fiNotificationRequest.getFIStatusNotification().getFIStatusResponse());
        stringObjectHashMap.put("notifier.Id", fiNotificationRequest.getNotifier().getId());
        stringObjectHashMap.put("notifier.type", fiNotificationRequest.getNotifier().getType());
        // iterate map and set the message for empty or null values
        for (String key : stringObjectHashMap.keySet())
        {
            if(NullEmptyUtils.isNull(stringObjectHashMap.get(key)) ||stringObjectHashMap.get(key).equals("")){
                errorMessage = errorMessage + key+",";
            }
        }
        return errorMessage;
    }

    boolean checkSessionStatus(FINotificationRequest fiNotificationRequest){
        boolean isSessionStatusPresent = false;
        for (SessionStatus c : SessionStatus.values()) {
            if (c.name().contains(fiNotificationRequest.getFIStatusNotification().getSessionStatus())) {
                isSessionStatusPresent = true;
            }
        }
        return isSessionStatusPresent;
    }

    void fiNotificationCallBack(ConsentEntity consentEntity, FIRequestEntity fiRequestEntity, String fiStatus) throws JWSSignatureException, DataException {
        FINotificationErrorResponseToFIU fiNotificationErrorResponseToFIU = new FINotificationErrorResponseToFIU();
        fiNotificationErrorResponseToFIU.setFiuConnectSessionId(consentEntity.getFiuConnectSessionId());
        fiNotificationErrorResponseToFIU.setFiStatus(fiStatus);
        fiNotificationErrorResponseToFIU.setVer(applicationConfigurationBean.getFiuConnectVersion());
        fiNotificationErrorResponseToFIU.setTimestamp(DateTimeUtil.getISOTimeStamp(System.currentTimeMillis()));
        fiNotificationErrorResponseToFIU.setTxnid(UUIDGenerator.generateUUID());
        fiNotificationErrorResponseToFIU.setErrorMsg(GeneralConstants.FI_STATUS_MSG+fiStatus);
        fiNotificationErrorResponseToFIU.setErrorCode(GeneralConstants.INVALID_REQUEST);
        callBackService.fiNotificationCallBack(fiNotificationErrorResponseToFIU,
                consentEntity.getConsentDetail().getDataConsumer().getId(), MDC.get(applicationConfigurationBean.getMdcLogId()));

    }
