    @Override
    public String verifyAAApiKey(String aaApiKey) throws JWSSignatureException, DataException, InvalidRequestException, JoseException {

        if(NullEmptyUtils.isNullorEmpty(aaApiKey)){
            throw new DataException(
                    GeneralConstants.UNAUTHORIZED,
                    GeneralConstants.EMPTY_AA_API_KEY_MSG,
                    HttpStatus.UNAUTHORIZED);
        }

        List<String> split_string = Arrays.asList(aaApiKey.split("\\."));
        if(split_string.size() < 3){
            throw new DataException(
                    GeneralConstants.UNAUTHORIZED,
                    GeneralConstants.INVALID_AA_API_KEY_PROVIDED,
                    HttpStatus.UNAUTHORIZED);
        }

        String base64EncodedBody = split_string.get(1);
        Base64.Decoder decoder = Base64.getDecoder();
        String body = "";
        try {
            body = new String(decoder.decode(base64EncodedBody));
        } catch (IllegalArgumentException ile){
            throw new DataException(
                    GeneralConstants.UNAUTHORIZED,
                    GeneralConstants.INVALID_AA_API_KEY_PROVIDED,
                    HttpStatus.UNAUTHORIZED);
        }


        SignatureEntity signatureEntity = sahamtiTokenManagementService.getSahamatiPublicKey();
        signatureService.signatureVerification(new Verification(
                body, aaApiKey,
                signatureEntity));
        System.out.println("aa_api_key verified.");
        TokenRequestBody tokenRequestBody = (TokenRequestBody) JsonUtil.convertJsonToObject(body, TokenRequestBody.class);
        MDC.put("key_client_id", tokenRequestBody.getClientId());
        long currentTimeinMills = Calendar.getInstance().getTimeInMillis();
        System.out.println(currentTimeinMills);
        Date date=new Date(tokenRequestBody.getExp() * 1000);
        System.out.println("Expiry Date: " + date);
        if((tokenRequestBody.getExp() * 1000) < currentTimeinMills){
            throw new DataException(
                    GeneralConstants.INVALID_REQUEST,
                    GeneralConstants.AA_API_KEY_TOKEN_EXPIRED,
                    HttpStatus.BAD_REQUEST);
        }

        return tokenRequestBody.getClientId();
    }

    @Override
    public void verifyXJwsSignature(String xJwsSignature, String requestBody, String aaId) throws DataException {
        try
        {
            if(NullEmptyUtils.isNullorEmpty(xJwsSignature)){
                throw new DataException(
                        GeneralConstants.INVALID_SIGNATURE,
                        GeneralConstants.INVALID_SIGNATURE_MSG,
                        HttpStatus.BAD_REQUEST);
            }

