package com.finbit.fiuadapter.webservice.utils;

import java.io.Serializable;
import java.time.LocalDateTime;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;
import java.util.function.Function;

import javax.servlet.http.HttpServletRequest;
import javax.xml.bind.DatatypeConverter;

import org.springframework.beans.factory.annotation.Autowired;

import com.finbit.fiuadapter.webservice.security.CustomUser;
import com.finbit.fiuadapter.webservice.security.JwtConfig;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;

/**
 * @author Naman Bajaj
 *
 *         This class is a generic class for JWT token creation and validation of tokens.
 */
public class JwtTokenUtil implements Serializable {

    @Autowired
    private transient JwtConfig jwtConfig;

    private static final long serialVersionUID = -2550185165626007488L;

    /**
     *
     * @param token
     * @return Expiration of the given token
     */

    private Date getExpirationDateFromToken( String token )
    {
        return getClaimFromToken(token, Claims::getExpiration);
    }

    /**
     *
     * @param token
     * @param claimsResolver
     * @param <T>
     * @return Returns particular requested Claims from the Function
     */

    public <T> T getClaimFromToken( String token, Function<Claims, T> claimsResolver )
    {
        final Claims claims = getAllClaimsFromToken(token);
        return claimsResolver.apply(claims);
    }

    /**
     *
     * @param token
     * @return All claims from the token
     */

    private Claims getAllClaimsFromToken( String token )
    {
        return Jwts.parser().setSigningKey(DatatypeConverter.parseBase64Binary(jwtConfig.getSecret()))
                .parseClaimsJws(token).getBody();
    }

    /**
     *
     * @param token
     * @return Checks whether the token is expired or not
     */
    private Boolean isTokenExpired( String token )
    {
        final Date expiration = getExpirationDateFromToken(token);
        return expiration.before(new Date());
    }

    /**
     *
     * @param user
     * @return Generates token with HS512 algorithm
     */

    public String generateToken( CustomUser user )
    {
        Map<String, Object> claims = new HashMap<>();
        claims.put("username", user.getFiuId());
        claims.put(jwtConfig.getFiuId(), user.getUsername());
        claims.put("scope", "login");
        claims.put("type", "user");
        claims.put("creation", LocalDateTime.now());
        return doGenerateToken(claims, user.getUsername());
    }

    /**
     *
     * @param claims
     * @param subject
     * @return String token
     */

    private String doGenerateToken( Map<String, Object> claims, String subject )
    {
        return Jwts.builder().setClaims(claims).setSubject(subject).setIssuedAt(new Date(System.currentTimeMillis()))
                .setExpiration(new Date(System.currentTimeMillis() + jwtConfig.getExpiration() * 1000))
                .signWith(SignatureAlgorithm.HS512, DatatypeConverter.parseBase64Binary(jwtConfig.getSecret()))
                .compact();
    }

    /**
     *
     * @param token
     * @return Validating the token for verification in the Header
     */
    public Boolean validateToken( String token )
    {
        String username = getClaimFromToken(token, Claims::getSubject);
        final String user = getUsernameFromToken(token);
        return (user.equals(username) && !isTokenExpired(token));
    }

    /**
     *
     * @param token
     * @return Username from Token
     */
    public String getUsernameFromToken( String token )
    {
        return getClaimFromToken(token, Claims::getSubject);
    }

    /**
     *
     * @param token
     * @return Username from Token
     */
    public String getFiuIdFromToken( String token )
    {
        Claims claims = Jwts.parser().setSigningKey(jwtConfig.getSecret()).parseClaimsJws(token).getBody();
        return claims.get(jwtConfig.getFiuId()).toString();
    }

    /**
     *
     * @param httpServletRequest
     * @return Token
     */

    public String getTokenFromHttpServletRequest( HttpServletRequest httpServletRequest )
    {
        String header = httpServletRequest.getHeader(jwtConfig.getHeader());
        if( header.startsWith(jwtConfig.getPrefix()) )
        {
            return header.replace(jwtConfig.getPrefix(), "");
        }
        return null;
    }
