package com.finbit.fiuadapter.webservice.utils;

import java.beans.FeatureDescriptor;
import java.util.stream.Stream;

import org.springframework.beans.BeanUtils;
import org.springframework.beans.BeanWrapper;
import org.springframework.beans.BeanWrapperImpl;

/**
 * @author manjunathr created at 12-11-2020
 *         <p>
 *         This is the Util class used for the opertations related to Objects
 */
public class BeansUtils {

    /**
     * This method will copy one object to another object
     */
    public static void copyProperties( Object source, Object destination, boolean ignoreNullProperties )
    {
        if( ignoreNullProperties )
            BeanUtils.copyProperties(source, destination, getNullPropertyNames(source));
        else
            BeanUtils.copyProperties(source, destination);

    }

    private static String[] getNullPropertyNames( Object source )
    {
        final BeanWrapper wrappedSource = new BeanWrapperImpl(source);
        return Stream.of(wrappedSource.getPropertyDescriptors()).map(FeatureDescriptor::getName)
                .filter(propertyName -> wrappedSource.getPropertyValue(propertyName) == null).toArray(String[]::new);
    }
}

