import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;

/**
 * @author manjunathr Created on 18-07-2020
 *
 *         This Util class is used for the IO stream operations
 */
@Slf4j
public class HttpContentExtractorUtil {

    /**
     * This method is used to get the request body from the HTTP Servlet Request Object
     *
     * @param inputStream
     * @return converted request body to JSON String
     * @throws JWSSignatureException
     */
    public static String getDataByInputStream( InputStream inputStream ) throws DataException, JsonFormatException {
        try
        {
            BufferedReader bufferedReader = new BufferedReader(new InputStreamReader(inputStream));
            return bufferedReader.lines().collect(Collectors.joining());
        } catch( Exception e )
        {
            log.error("Error while getting Request body", e);
            throw new DataException(e);
        }
    }

    public static String handleRequest( CachedBodyHttpServletRequest req ) throws JWSSignatureException
    {
        HashMap<String, String> paramsHashMap = new HashMap<>();
        Enumeration<String> parameterNames = req.getParameterNames();

        while( parameterNames.hasMoreElements() )
        {
            String paramName = parameterNames.nextElement();

            String[] paramValues = req.getParameterValues(paramName);
            for( String paramValue : paramValues )
            {
                paramsHashMap.put(paramName, paramValue);
            }

        }
        return JsonUtil.convertObjectToJson(paramsHashMap);
    }
}
